#!/usr/bin/env python3
"""Run ns-3-ub simulation for traffic generated by tools/all2allv_snack.py."""

from __future__ import annotations

import argparse
import csv
import html
import importlib.util
import statistics
import sys
from pathlib import Path

import run_alltoallv_snake_plane_experiment as snake


REPO_ROOT = Path(__file__).resolve().parents[1]
SNACK_PATH = REPO_ROOT / "tools/all2allv_snack.py"
BASE = REPO_ROOT / "experiments/ubx16/alltoallv/snack"
CASES = BASE / "cases"
REPORTS = BASE / "reports"
PROFILES = BASE / "profiles"


def load_snack_module():
    spec = importlib.util.spec_from_file_location("all2allv_snack", SNACK_PATH)
    if spec is None or spec.loader is None:
        raise RuntimeError(f"cannot load {SNACK_PATH}")
    module = importlib.util.module_from_spec(spec)
    sys.modules[spec.name] = module
    spec.loader.exec_module(module)
    return module


def write_csv(path: Path, fields: list[str], rows: list[dict[str, object]]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("w", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=fields)
        writer.writeheader()
        writer.writerows(rows)


def generate_tasks(scheme: str, ratio: float, min_bytes: int, seed: int, recv_exclusive: bool = True):
    snack = load_snack_module()
    snack.SCHEME = scheme
    snack.DATA_RATIO = ratio
    snack.MIN_DATA_SIZE_BYTE = min_bytes
    snack.RANDOM_SEED = seed
    snack.ENABLE_RECV_PLANE_EXCLUSIVE_DEP = recv_exclusive
    matrix = snack.generate_random_matrix()
    tasks = snack.build_tasks(matrix)
    snack.apply_intra_pod_policy(tasks)
    snack.assign_planes_for_cross_pod_tasks(tasks)
    snack.build_source_plane_dependencies(tasks)
    snack.build_receiver_plane_dependencies(tasks)
    sizes = {
        (src, dst): matrix[src][dst]
        for src in range(snack.NUM_RANKS)
        for dst in range(snack.NUM_RANKS)
        if src != dst
    }
    return snack, matrix, tasks, sizes


def write_snack_case(case_dir: Path, tasks, sizes: dict[tuple[int, int], int]) -> dict[str, float]:
    snake.copy_base(case_dir)
    fields, by_pair = snake.load_tp_rows()
    direct_ports = snake.load_direct_ports()

    selected_rows: list[dict[str, str]] = []
    for src in range(snake.RANK_COUNT):
        for dst in range(src + 1, snake.RANK_COUNT):
            rows = by_pair[(src, dst)]
            if snake.same_group(src, dst):
                row = dict(snake.select_direct_row(rows, direct_ports[(src, dst)]))
                row["priority"] = str(snake.PRIORITY)
                selected_rows.append(row)
            else:
                for plane in range(snake.PLANE_COUNT):
                    row = dict(snake.select_plane_row(rows, plane))
                    row["priority"] = str(snake.plane_priority(plane))
                    selected_rows.append(row)
    write_csv(case_dir / "transport_channel.csv", fields, selected_rows)

    traffic: list[dict[str, object]] = []
    plane_bytes = [0] * snake.PLANE_COUNT
    dst_plane_counts: dict[tuple[int, int], int] = {}
    debug_rows: list[dict[str, object]] = []
    for task in sorted(tasks, key=lambda t: t.taskId):
        priority = snake.PRIORITY if not task.isCrossPod else snake.plane_priority(int(task.actualPlane))
        depends = " ".join(str(dep) for dep in task.dependOnPhases)
        traffic.append(
            {
                "taskId": task.taskId,
                "sourceNodeId": task.sourceNodeId,
                "destNodeId": task.destNodeId,
                "dataSize(Byte)": task.dataSizeByte,
                "opType": task.opType,
                "priority": priority,
                "delay": task.delay,
                "phaseId": task.phaseId,
                "dependOnPhases": depends,
            }
        )
        debug_rows.append(
            {
                **traffic[-1],
                "sourcePod": task.sourcePod,
                "destPod": task.destPod,
                "isCrossPod": int(task.isCrossPod),
                "logicalRound": "" if task.logicalRound is None else task.logicalRound,
                "basePlane": "" if task.basePlane is None else task.basePlane,
                "actualPlane": "" if task.actualPlane is None else task.actualPlane,
                "sourcePlanePrevPhase": "" if task.sourcePlanePrevPhase is None else task.sourcePlanePrevPhase,
                "recvPlanePrevPhase": "" if task.recvPlanePrevPhase is None else task.recvPlanePrevPhase,
            }
        )
        if task.isCrossPod:
            plane = int(task.actualPlane)
            plane_bytes[plane] += task.dataSizeByte
            key = (task.destNodeId, plane)
            dst_plane_counts[key] = dst_plane_counts.get(key, 0) + 1

    write_csv(case_dir / "traffic.csv", snake.TRAFFIC_HEADER, traffic)
    write_csv(
        case_dir / "traffic_debug_with_plane.csv",
        snake.TRAFFIC_HEADER
        + [
            "sourcePod",
            "destPod",
            "isCrossPod",
            "logicalRound",
            "basePlane",
            "actualPlane",
            "sourcePlanePrevPhase",
            "recvPlanePrevPhase",
        ],
        debug_rows,
    )
    return {
        "plane0_bytes": float(plane_bytes[0]),
        "plane1_bytes": float(plane_bytes[1]),
        "plane2_bytes": float(plane_bytes[2]),
        "plane3_bytes": float(plane_bytes[3]),
        "plane_cv": statistics.pstdev(plane_bytes) / statistics.mean(plane_bytes),
        "max_dst_plane_queue": float(max(dst_plane_counts.values()) if dst_plane_counts else 0),
    }


def render_profile(row: dict[str, object]) -> str:
    case = Path(str(row["case"]))
    name = f"{case.name}-rank0-profile.html"
    out = PROFILES / name
    if str(row["algorithm"]) == "baseline":
        cmd = [
            "python3",
            "tools/render_ns3ub_mesh1d_rank_profile.py",
            str(case),
            "-o",
            str(out),
            "--rank",
            "0",
            "--concurrent",
            "16",
            "--title",
            f"UBX16 AllToAllV snack {row['algorithm']} | rank0",
        ]
    else:
        cmd = [
            "python3",
            "tools/render_ns3ub_rank_profile.py",
            str(case),
            "-o",
            str(out),
            "--rank",
            "0",
            "--rank-count",
            "16",
            "--group-size",
            "4",
            "--source-case",
            str(snake.SOURCE_CASE),
            "--priorities",
            "3",
            "4",
            "5",
            "6",
            "7",
            "--unit-mode",
            "priority-plane",
            "--title",
            f"UBX16 AllToAllV snack {row['algorithm']} | rank0",
        ]
    snake.run_cmd(cmd)
    return f"../profiles/{name}"


def write_summary(path: Path, rows: list[dict[str, object]]) -> None:
    fields = [
        "algorithm",
        "case",
        "tasks",
        "total_bytes",
        "pair_avg_bytes",
        "pair_min_bytes",
        "pair_max_bytes",
        "pair_cv",
        "src_min_bytes",
        "src_max_bytes",
        "src_max_min_ratio",
        "src_cv",
        "dst_cv",
        "cross_fraction",
        "plane0_bytes",
        "plane1_bytes",
        "plane2_bytes",
        "plane3_bytes",
        "plane_cv",
        "max_dst_plane_queue",
        "makespan_us",
        "global_GBps",
        "single_rank_GBps",
        "rank0_makespan_us",
        "rank0_GBps",
        "profile",
    ]
    write_csv(path, fields, rows)


def render_report(rows: list[dict[str, object]], output: Path, ratio: float, min_bytes: int, seed: int) -> None:
    baseline = next(row for row in rows if row["algorithm"] == "baseline")
    base_gbps = float(baseline["single_rank_GBps"])
    trs = []
    for row in rows:
        gbps = float(row["single_rank_GBps"])
        trs.append(
            f"""<tr>
  <td>{html.escape(str(row['algorithm']))}</td>
  <td>{float(row['makespan_us']):.3f}</td>
  <td>{gbps:.2f}</td>
  <td class="{'good' if gbps >= base_gbps else 'bad'}">{(gbps / base_gbps - 1.0) * 100:+.1f}%</td>
  <td>{float(row['plane_cv']):.3f}</td>
  <td>{float(row['max_dst_plane_queue']):.0f}</td>
  <td><a href="{html.escape(str(row['profile']))}">rank0</a></td>
  <td><code>{html.escape(Path(str(row['case'])).name)}</code></td>
</tr>"""
        )

    output.write_text(
        f"""<!doctype html>
<html lang="zh-CN">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>UBX16 AllToAllV Snack Script Experiment</title>
  <style>
    :root {{ --bg:#f6f7f9; --panel:#fff; --text:#1f2937; --muted:#667085; --line:#d8dee8; --good:#087443; --bad:#b42318; --blue:#2563eb; }}
    * {{ box-sizing:border-box; }}
    body {{ margin:0; background:var(--bg); color:var(--text); font:14px/1.55 -apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif; }}
    main {{ width:min(1120px, calc(100% - 36px)); margin:26px auto 48px; }}
    h1 {{ margin:0 0 8px; font-size:28px; letter-spacing:0; }}
    h2 {{ margin:0 0 12px; font-size:18px; letter-spacing:0; }}
    section, .metric {{ background:var(--panel); border:1px solid var(--line); border-radius:8px; padding:16px; }}
    .muted {{ color:var(--muted); }}
    .metrics {{ display:grid; grid-template-columns:repeat(4,minmax(0,1fr)); gap:12px; margin:18px 0; }}
    .metric span {{ display:block; color:var(--muted); font-size:12px; }}
    .metric strong {{ display:block; margin-top:4px; font-size:22px; }}
    .layout {{ display:grid; gap:14px; }}
    table {{ width:100%; border-collapse:collapse; table-layout:fixed; font-variant-numeric:tabular-nums; }}
    th, td {{ border-bottom:1px solid var(--line); padding:8px 7px; text-align:right; white-space:nowrap; overflow:hidden; text-overflow:ellipsis; }}
    th:first-child, td:first-child, th:nth-last-child(-n+2), td:nth-last-child(-n+2) {{ text-align:left; }}
    th {{ color:var(--muted); font-size:12px; background:#fbfcfe; }}
    a {{ color:var(--blue); text-decoration:none; font-weight:650; }}
    a:hover {{ text-decoration:underline; }}
    code {{ background:#eef2f7; border-radius:5px; padding:1px 5px; }}
    .good {{ color:var(--good); }}
    .bad {{ color:var(--bad); }}
    ul {{ margin:8px 0 0 18px; padding:0; }}
    li {{ margin:5px 0; }}
  </style>
</head>
<body>
<main>
  <header>
    <h1>UBX16 AllToAllV Snack Script Experiment</h1>
    <p class="muted">输入流量来自 <code>tools/all2allv_snack.py</code> 的随机矩阵和依赖编排。注意：原始 simulator CSV 不显式携带 plane；这里用脚本内部 <code>actualPlane</code> 转换成 ns3 priority 3/4/5/6，才是固定平面语义。</p>
  </header>
  <div class="metrics">
    <div class="metric"><span>seed</span><strong>{seed}</strong></div>
    <div class="metric"><span>single-task max/min</span><strong>{ratio:.2f}x</strong></div>
    <div class="metric"><span>min task</span><strong>{min_bytes / 1024 / 1024:.1f}MiB</strong></div>
    <div class="metric"><span>baseline</span><strong>{base_gbps:.2f}</strong><span>GB/s per rank</span></div>
  </div>
  <div class="layout">
    <section>
      <h2>结果</h2>
      <table>
        <thead><tr><th>算法</th><th>makespan us</th><th>GB/s/rank</th><th>vs baseline</th><th>plane CV</th><th>max dst-plane queue</th><th>profile</th><th>case</th></tr></thead>
        <tbody>
{''.join(trs)}
        </tbody>
      </table>
    </section>
    <section>
      <h2>判断</h2>
      <ul>
        <li><code>snack-v0</code> 使用脚本的 <code>actualPlane=basePlane</code>；<code>snack-v1</code> 使用 <code>(basePlane + src % 4) % 4</code>。</li>
        <li>跨 Pod 流按 source-plane 和 dest-plane 加静态依赖；Pod 内 mesh 流不加额外依赖。</li>
        <li>如果 snack 比 baseline 低，主要原因通常是固定平面每个 peer 只走单 TP，而 baseline full-TP 可以对同一 peer 使用多条 TP 分摊。</li>
      </ul>
    </section>
  </div>
</main>
</body>
</html>
"""
    )


def main() -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--ratio", type=float, default=1.2)
    parser.add_argument("--min-bytes", type=int, default=1_048_576)
    parser.add_argument("--seed", type=int, default=4)
    parser.add_argument("--docker-container", default="hcomm-dev")
    parser.add_argument("--mtp-threads", type=int, default=8)
    parser.add_argument(
        "--no-recv-exclusive",
        action="store_true",
        help="Disable dest+plane receiver exclusive dependency; keep source+plane dependency only.",
    )
    parser.add_argument("--no-run", action="store_true")
    args = parser.parse_args()

    recv_exclusive = not args.no_recv_exclusive
    _, _, tasks_v1, sizes = generate_tasks("v1", args.ratio, args.min_bytes, args.seed, recv_exclusive)
    dep_tag = "recvdep" if recv_exclusive else "srconly"
    suffix = f"ratio{str(args.ratio).replace('.', 'p')}_seed{args.seed}_{args.min_bytes // 1024 // 1024}mibmin_{dep_tag}"
    scenarios = [
        ("baseline", CASES / f"generated_topology_ubx16_a2av_snack_baseline_{suffix}", None, {}),
        ("snack-v0", CASES / f"generated_topology_ubx16_a2av_snack_v0_{suffix}", "v0", {}),
        ("snack-v1", CASES / f"generated_topology_ubx16_a2av_snack_v1_{suffix}", "v1", {}),
    ]
    summaries: list[dict[str, object]] = []
    for algorithm, case_dir, scheme, _ in scenarios:
        if algorithm == "baseline":
            snake.write_baseline_case(case_dir, sizes)
            extra = {
                "plane0_bytes": 0.0,
                "plane1_bytes": 0.0,
                "plane2_bytes": 0.0,
                "plane3_bytes": 0.0,
                "plane_cv": 0.0,
                "max_dst_plane_queue": 0.0,
            }
        else:
            _, _, tasks, _ = generate_tasks(str(scheme), args.ratio, args.min_bytes, args.seed, recv_exclusive)
            extra = write_snack_case(case_dir, tasks, sizes)
        if not args.no_run:
            snake.run_sim(case_dir, args.docker_container, args.mtp_threads)
            summary = snake.summarize(case_dir, sizes, extra)
            summaries.append({"algorithm": algorithm, "case": str(case_dir.relative_to(REPO_ROOT)), **summary})
            print(f"{algorithm}: makespan={summary['makespan_us']:.3f}us single_rank={summary['single_rank_GBps']:.2f}GB/s")

    if summaries:
        REPORTS.mkdir(parents=True, exist_ok=True)
        PROFILES.mkdir(parents=True, exist_ok=True)
        for row in summaries:
            row["profile"] = render_profile(row)
        summary_path = REPORTS / f"ns3ub-ubx16-alltoallv-snack-{suffix}-summary.csv"
        report_path = REPORTS / f"ns3ub-ubx16-alltoallv-snack-{suffix}-report.html"
        write_summary(summary_path, summaries)
        render_report(summaries, report_path, args.ratio, args.min_bytes, args.seed)
        print(f"summary={summary_path}")
        print(f"report={report_path}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
